parameters.jsCode:
const body = $input.first().json.body || $input.first().json;
const event = body;
const invoice = event?.data?.object || {};

const customerId = invoice.customer || '';
const invoiceId = invoice.id || '';
const attemptCount = invoice.attempt_count || 1;
const nextPaymentAttempt = invoice.next_payment_attempt || null;
const amountDue = invoice.amount_due || 0;
const currency = (invoice.currency || 'usd').toUpperCase();
const amountDisplay = `$${(amountDue / 100).toFixed(2)} ${currency}`;

const nextRetryDisplay = nextPaymentAttempt
  ? new Date(nextPaymentAttempt * 1000).toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })
  : 'No automatic retry scheduled';

const isSuspended = attemptCount >= 3;

return [{ json: {
  customerId,
  invoiceId,
  attemptCount,
  nextPaymentAttempt,
  nextRetryDisplay,
  amountDue,
  amountDisplay,
  currency,
  isSuspended,
  updatedAt: new Date().toISOString(),
  rawPayload: JSON.stringify(body)
} }];

const users = $input.first().json;
const user = Array.isArray(users) ? users[0] : users;
const parsed = $('Parse Payment Failed Payload').first().json;
return [{ json: {
  ...parsed,
  email: user?.email || '',
  firstName: user?.first_name || 'there'
} }];

const data = $input.first().json;
const patch = {
  payment_status: 'past_due',
  updated_at: data.updatedAt
};
if (data.isSuspended) {
  patch.plan_status = 'suspended';
}
return [{ json: { ...data, patch } }];

